import { useState } from "react";
import axios from "axios";
import { useParams } from "react-router-dom";

export default function Register() {

  const { role } = useParams();

  const [form, setForm] = useState({
    role
  });

  const register = async () => {

    if (role === "labour") {

      form.skills = form.skills.split(",");

    }

    await axios.post(
      "http://localhost:5000/api/auth/register",
      form
    );

    alert("Registration Successful");

    window.location = `/login/${role}`;
  };

  return (
    <div style={styles.page}>

      <div style={styles.card}>

        <h1>{role} Register</h1>

        <input
          style={styles.input}
          placeholder="Name"
          onChange={(e) =>
            setForm({ ...form, name: e.target.value })
          }
        />

        <input
          style={styles.input}
          placeholder="Email"
          onChange={(e) =>
            setForm({ ...form, email: e.target.value })
          }
        />

        <input
          style={styles.input}
          placeholder="Password"
          onChange={(e) =>
            setForm({ ...form, password: e.target.value })
          }
        />

        {role === "labour" && (

          <>
            <input
              style={styles.input}
              placeholder="Skills (comma separated)"
              onChange={(e) =>
                setForm({
                  ...form,
                  skills: e.target.value
                })
              }
            />

            <input
              style={styles.input}
              placeholder="Expected Base Price"
              onChange={(e) =>
                setForm({
                  ...form,
                  price: e.target.value
                })
              }
            />
          </>
        )}

        <button style={styles.btn} onClick={register}>
          Register
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  card: {
    width: "400px",
    background: "white",
    padding: "35px",
    borderRadius: "20px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.08)"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginTop: "15px",
    borderRadius: "10px",
    border: "1px solid #ddd"
  },

  btn: {
    width: "100%",
    padding: "14px",
    marginTop: "20px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  }
};
